,"name":"batchId","type":"uint256"}],"name":"getFishBatch","outputs":[{"internalType":"uint256","name":"","type":"uint256"},{"internalType":"address","name":"","type":"address"},{"internalType":"uint256","name":"","type":"uint256"},{"internalType":"uint256","name":"","type":"uint256"},{"internalType":"bool","name":"","type":"bool"},{"internalType":"bool","name":"","type":"bool"},{"internalType":"bool","name":"","type":"bool"},{"internalType":"uint256[]","name":"","type":"uint256[]"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"uint256","name":"batchId","type":"uint256"}],"name":"getTransferIds","outputs":[{"internalType":"uint256[]","name":"","type":"uint256[]"}],"stateMutability":"view","type":"function"},{"inputs":[],"name":"government","outputs":[{"internalType":"address","name":"","type":"address"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"uint256","name":"weight","type":"uint256"},{"internalType":"uint256","name":"pricePerKg","type":"uint256"}],"name":"logCatch","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[],"name":"nextBatchId","outputs":[{"internalType":"uint256","name":"","type":"uint256"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"uint256","name":"batchId","type":"uint256"},{"internalType":"string","name":"reason","type":"string"}],"name":"raiseDispute","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"uint256","name":"batchId","type":"uint256"},{"internalType":"bool","name":"sustainable","type":"bool"}],"name":"updateSustainability","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"uint256","name":"batchId","type":"uint256"},{"internalType":"uint256","name":"weight","type":"uint256"}],"name":"updateweight","outputs":[],"stateMutability":"nonpayable","type":"function"}],"devdoc":{"kind":"dev","methods":{},"version":1},"userdoc":{"kind":"user","methods":{},"version":1}},"settings":{"compilationTarget":{"contracts/FisheriesManagement.sol":"FisheriesManagement"},"evmVersion":"paris","libraries":{},"metadata":{"bytecodeHash":"ipfs","useLiteralContent":true},"optimizer":{"enabled":true,"runs":200},"remappings":[]},"sources":{"contracts/FisheriesManagement.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

contract FisheriesManagement {
    address public government;
    uint256 public nextBatchId = 1;

    struct FishBatch {
        uint256 id;
        address fisher;
        uint256 weight;
        uint256 pricePerKg;
        bool isSold;
        bool inDispute;
        bool sustainable;
        uint256[] transferIds;
    }

    mapping(uint256 => FishBatch) public batches;

    event FishLogged(
        uint256 batchId,
        address fisher,
        uint256 weight,
        uint256 pricePerKg
    );
    event SustainabilityUpdated(uint256 batchId, bool sustainable);
    event DisputeRaised(uint256 batchId, string reason);

    modifier onlyGovernment() {
        require(
            msg.sender == government,
            "Only government can call this function"
        );
        _;
    }

    constructor() {
        government = msg.sender;
    }

    function logCatch(uint256 weight, uint256 pricePerKg) public {
        batches[nextBatchId] = FishBatch(
            nextBatchId,
            msg.sender,
            weight,
            pricePerKg,
            false,
            false,
            false,
            new uint256[](0)
        );
        emit FishLogged(nextBatchId, msg.sender, weight, pricePerKg);
        nextBatchId++;
    }

    function updateSustainability(
        uint256 batchId,
        bool sustainable
    ) public onlyGovernment {
        batches[batchId].sustainable = sustainable;
        emit SustainabilityUpdated(batchId, sustainable);
    }

    function raiseDispute(
        uint256 batchId,
        string memory reason
    ) public onlyGovernment { // *************************************
        batches[batchId].inDispute = true;
        emit DisputeRaised(batchId, reason);
    }




function getFishBatch(uint256 batchId) external view returns (
        uint256,
        address,
        uint256,
        uint256,
        bool,
        bool,
        bool,
        uint256[] memory
    ){
    require(batches[batchId].id == batchId, "Batch does not exist");
    FishBatch memory batch = batches[batchId];
    return (
        batch.id,
        batch.fisher,
        batch.weight,
        batch.pricePerKg,
        batch.isSold,
        batch.inDispute,
        batch.sustainable,
        batch.transferIds
    );
}



    function getBatchSustainability(
        uint256 batchId
    ) external view returns (bool) {
        return batches[batchId].sustainable;
    }

    function getTransferIds(
        uint256 batchId
    ) external view returns (uint256[] memory) {
        require(batches[batchId].id == batchId, "Batch does not exist");
        return batches[batchId].transferIds;
    }

    function addTransferToBatch(uint256 batchId, uint256 transferId) external {
        require(batches[batchId].id == batchId, "Batch does not exist");
        batches[batchId].transferIds.push(transferId);
    }

    function updateweight(uint256 batchId, uint256 weight) external {
        require(batches[batchId].id == batchId, "Batch does not exist");
        batches[batchId].weight -= weight;
    }
}
