ility":"nonpayable","type":"function"},{"inputs":[{"internalType":"address","name":"addr","type":"address"}],"name":"setFisheriesManagement","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"address","name":"addr","type":"address"}],"name":"setInspectorAuthorization","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"address","name":"addr","type":"address"}],"name":"setMarketplace","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[{"internalType":"uint256","name":"","type":"uint256"}],"name":"stolenBatches","outputs":[{"internalType":"bool","name":"","type":"bool"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"uint256","name":"amount","type":"uint256"},{"internalType":"address payable","name":"to","type":"address"}],"name":"withdraw","outputs":[],"stateMutability":"nonpayable","type":"function"},{"stateMutability":"payable","type":"receive"}],"devdoc":{"kind":"dev","methods":{},"version":1},"userdoc":{"kind":"user","methods":{},"version":1}},"settings":{"compilationTarget":{"contracts/Govt.sol":"Govt"},"evmVersion":"paris","libraries":{},"metadata":{"bytecodeHash":"ipfs","useLiteralContent":true},"optimizer":{"enabled":true,"runs":200},"remappings":[]},"sources":{"contracts/FishMarketplace.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {FisheriesManagement} from "./FisheriesManagement.sol";

contract FishMarketplace {
    FisheriesManagement fisheriesManagement;
    address public pricingAdjustmentContract;

    struct Listing {
        uint256 listingId;
        uint256 batchId;
        address fisher;
        uint256 totalWeight;
        uint256 availableWeight;
        uint256 pricePerKg;
        bool isSoldOut;
    }

    mapping(uint256 => Listing) public listings;
    uint256 public nextListingId = 1;

    event FishListed(
        uint256 listingId,
        uint256 batchId,
        uint256 weight,
        uint256 pricePerKg
    );
    event FishBought(
        uint256 listingId,
        address buyer,
        uint256 weight,
        uint256 totalPrice
    );
    event PriceUpdated(uint256 listingId, uint256 newPricePerKg);

    constructor(address fisheriesManagementAddress) {
        fisheriesManagement = FisheriesManagement(fisheriesManagementAddress);
    }

    modifier onlyPricingAdjustment() {
        require(msg.sender == pricingAdjustmentContract, "Unauthorized: Only the PricingAdjustment contract can adjust prices");
        _;
    }


    function setPricingAdjustmentContract(
        address _pricingAdjustmentContract
    ) external {
        require(
            pricingAdjustmentContract == address(0),
            "Pricing adjustment contract already set"
        );
        pricingAdjustmentContract = _pricingAdjustmentContract;
    }

    function listFish(
        uint256 batchId,
        uint256 weight,
        uint256 pricePerKg
    ) public {
        require(
            fisheriesManagement.getBatchSustainability(batchId),
            "Batch is not sustainable"
        );
        fisheriesManagement.updateweight(batchId, weight);
        listings[nextListingId] = Listing(
            nextListingId,
            batchId,
            msg.sender,
            weight,
            weight,
            pricePerKg,
            false
        );
        emit FishListed(nextListingId, batchId, weight, pricePerKg);
        nextListingId++;
    }

    function buyFish(uint256 listingId, uint256 weight) public payable {
        Listing storage listing = listings[listingId];
        require(!listing.isSoldOut, "Listing is sold out");
        require(
            weight <= listing.availableWeight,
            "Not enough weight available"
        );

        uint256 totalPrice = weight * listing.pricePerKg;
        require(msg.value >= totalPrice, "Insufficient funds");

        listing.availableWeight -= weight;
        if (listing.availableWeight == 0) {
            listing.isSoldOut = true;
        }
        payable(listing.fisher).transfer(totalPrice);
        emit FishBought(listingId, msg.sender, weight, totalPrice);
    }

    // New function to allow only authorized contract to adjust prices
    function adjustListingPrice(
        uint256 listingId,
        uint256 newPricePerKg
    ) external onlyPricingAdjustment {
        Listing storage listing = listings[listingId];
        listing.pricePerKg = newPricePerKg;
        emit PriceUpdated(listingId, newPricePerKg);
    }

    // New getter function to access listing details
    function getListingDetails(
        uint256 listingId
    )
        external
        view
        returns (uint256, uint256, address, uint256, uint256, uint256, bool)
    {
        Listing storage listing = listings[listingId];
        return (
            listing.listingId,
            listing.batchId,
            listing.fisher,
            listing.totalWeight,
            listing.availableWeight,
            listing.pricePerKg,
            listing.isSoldOut
        );
    }
}
","keccak256":"0xbf8c431de0fd91bb5a801b61f8151d4a3fb029fddf61f6253eaedca81c8bd08e","license":"MIT"},"contracts/FisheriesManagement.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

contract FisheriesManagement {
    address public government;
    uint256 public nextBatchId = 1;

    struct FishBatch {
        uint256 id;
        address fisher;
        uint256 weight;
        uint256 pricePerKg;
        bool isSold;
        bool inDispute;
        bool sustainable;
        uint256[] transferIds;
    }

    mapping(uint256 => FishBatch) public batches;

    event FishLogged(
        uint256 batchId,
        address fisher,
        uint256 weight,
        uint256 pricePerKg
    );
    event SustainabilityUpdated(uint256 batchId, bool sustainable);
    event DisputeRaised(uint256 batchId, string reason);

    modifier onlyGovernment() {
        require(
            msg.sender == government,
            "Only government can call this function"
        );
        _;
    }

    constructor() {
        government = msg.sender;
    }

    function logCatch(uint256 weight, uint256 pricePerKg) public {
        batches[nextBatchId] = FishBatch(
            nextBatchId,
            msg.sender,
            weight,
            pricePerKg,
            false,
            false,
            false,
            new uint256[](0)
        );
        emit FishLogged(nextBatchId, msg.sender, weight, pricePerKg);
        nextBatchId++;
    }

    function updateSustainability(
        uint256 batchId,
        bool sustainable
    ) public onlyGovernment {
        batches[batchId].sustainable = sustainable;
        emit SustainabilityUpdated(batchId, sustainable);
    }

    function raiseDispute(
        uint256 batchId,
        string memory reason
    ) public onlyGovernment { // *************************************
        batches[batchId].inDispute = true;
        emit DisputeRaised(batchId, reason);
    }




function getFishBatch(uint256 batchId) external view returns (
        uint256,
        address,
        uint256,
        uint256,
        bool,
        bool,
        bool,
        uint256[] memory
    ){
    require(batches[batchId].id == batchId, "Batch does not exist");
    FishBatch memory batch = batches[batchId];
    return (
        batch.id,
        batch.fisher,
        batch.weight,
        batch.pricePerKg,
        batch.isSold,
        batch.inDispute,
        batch.sustainable,
        batch.transferIds
    );
}



    function getBatchSustainability(
        uint256 batchId
    ) external view returns (bool) {
        return batches[batchId].sustainable;
    }

    function getTransferIds(
        uint256 batchId
    ) external view returns (uint256[] memory) {
        require(batches[batchId].id == batchId, "Batch does not exist");
        return batches[batchId].transferIds;
    }

    function addTransferToBatch(uint256 batchId, uint256 transferId) external {
        require(batches[batchId].id == batchId, "Batch does not exist");
        batches[batchId].transferIds.push(transferId);
    }

    function updateweight(uint256 batchId, uint256 weight) external {
        require(batches[batchId].id == batchId, "Batch does not exist");
        batches[batchId].weight -= weight;
    }
}
